// Ouvre ton fichier HTML exporté dans le navigateur, puis colle ce script dans la console.
// Il produit un JSON (string) que tu peux copier.

(function () {
  function getText(el) {
    // Récupère le texte "humain" (en gérant les <br> et entités)
    const clone = el.cloneNode(true);
    // remplace <br> par \n
    clone.querySelectorAll('br').forEach(br => br.replaceWith('\n'));
    return clone.textContent.trim();
  }

  const conversations = Array.from(document.querySelectorAll('.conversation')).map(conv => {
    const title = conv.querySelector('h4')?.textContent?.trim() || 'Sans titre';
    const messages = Array.from(conv.querySelectorAll('pre.message')).map(pre => {
      const author = pre.querySelector('.author')?.textContent?.trim() || 'inconnu';
      const contentDiv = pre.querySelector('div:not(.author)');
      const text = contentDiv ? getText(contentDiv) : '';
      const html = contentDiv ? contentDiv.innerHTML.trim() : '';
      return { author, text, html };
    });

    return {
      name: title,
      url: null,                 // pas présent dans le HTML exporté
      created_at: null,          // sera fusionné depuis conversations.json
      created_by: null,          // idem
      tags: [],                  // à enrichir plus tard
      relations: { related_to: [] }, // à remplir au traitement
      messages
    };
  });

  const output = JSON.stringify({ conversations }, null, 2);
  console.log(output);
  // Option: télécharger un fichier
  const blob = new Blob([output], { type: 'application/json' });
  const a = document.createElement('a');
  a.href = URL.createObjectURL(blob);
  a.download = 'conversations_chatgpt_html.json';
  a.click();
})();

