// 1) npm init -y && npm i jsdom
// 2) node parse_export_html.js <chemin/fichier.html>
// 3) Écrit conversations_chatgpt_html.json à côté.

import { readFileSync, writeFileSync } from 'node:fs';
import { JSDOM } from 'jsdom';
import path from 'node:path';

function getTextFromElement(el) {
  const doc = el.ownerDocument;
  const clone = el.cloneNode(true);
  // <br> -> \n
  clone.querySelectorAll('br').forEach(br => br.replaceWith(doc.createTextNode('\n')));
  return clone.textContent.trim();
}

function parseHtml(html) {
  const dom = new JSDOM(html);
  const { document } = dom.window;

  const conversations = Array.from(document.querySelectorAll('.conversation')).map(conv => {
    const title = conv.querySelector('h4')?.textContent?.trim() || 'Sans titre';
    const messages = Array.from(conv.querySelectorAll('pre.message')).map(pre => {
      const author = pre.querySelector('.author')?.textContent?.trim() || 'inconnu';
      const contentDiv = pre.querySelector('div:not(.author)');
      const text = contentDiv ? getTextFromElement(contentDiv) : '';
      const htmlRaw = contentDiv ? contentDiv.innerHTML.trim() : '';
      return { author, text, html: htmlRaw };
    });

    return {
      name: title,
      url: null,
      created_at: null,
      created_by: null,
      tags: [],
      relations: { related_to: [] },
      messages
    };
  });

  return { conversations };
}

function main() {
  const inputPath = process.argv[2];
  if (!inputPath) {
    console.error('Usage: node parse_export_html.js <fichier.html>');
    process.exit(1);
  }
  const html = readFileSync(inputPath, 'utf8');
  const data = parseHtml(html);
  const outPath = path.join(path.dirname(inputPath), 'conversations_chatgpt_html.json');
  writeFileSync(outPath, JSON.stringify(data, null, 2), 'utf8');
  console.log('✅ Écrit :', outPath);
}

main();

